return $input.all().map((item) => {
  const link = item.json.Link;
  const match = link.match(/\/d\/([^/]+)\//);
  const fileId = match ? match[1] : null;

  if (fileId) {
    item.json.export_link = `https://drive.google.com/uc?export=download&id=${fileId}`;
  } else {
    item.json.export_link = link; // fallback
  }

  return item;
});

